const fs = require('fs');
const FILE = 'pariscore.html';
let h = fs.readFileSync(FILE, 'utf8');

const INSERT_AFTER = "  P2 DR</span><span style=\"opacity:.5\">— 1.0 parité</span></div>';\n}\n</script>";
const idx = h.indexOf(INSERT_AFTER);
if (idx === -1) { console.error('INSERT_AFTER not found'); process.exit(1); }

const MOMENTUM_BLOCK = [
'',
'<!-- ═══ MOMENTUM Popup : Force du joueur par jeu (graphe dual-courbe) ═══ -->',
'<div id="mom-popup-modal" class="tn2-modal" style="display:none;">',
'  <div class="tn2-modal-bd" onclick="closeMomPopup()"></div>',
'  <div class="tn2-modal-card" role="dialog" aria-modal="true" style="max-width:560px;padding:20px;">',
'    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px">',
'      <h3 style="font-family:var(--font-head,sans-serif);font-size:16px;font-weight:800;color:var(--text,#fff)">⚡ Force par jeu</h3>',
'      <a onclick="closeMomPopup()" style="cursor:pointer;color:var(--text3,#94a3b8);font-size:18px">✕</a>',
'    </div>',
'    <div id="mom-popup-content" style="min-height:200px"></div>',
'  </div>',
'</div>',
'<script>',
'// Ouvre le popup momentum',
'function openMomPopup(matchId) {',
'  try {',
'    var dataEl = document.getElementById("mom-popup-data-" + matchId);',
'    if (!dataEl) return;',
'    var data = JSON.parse(dataEl.textContent || "{}");',
'    var content = document.getElementById("mom-popup-content");',
'    var html = "";',
'    var p1n = data.p1n || "P1", p2n = data.p2n || "P2";',
'    var mom = data.momentum || {};',
'    var dir = mom.kfs_direction || "neutral";',
'    var conf = mom.kfs_confidence || 0;',
'    var dirLabel = dir === "p1" ? (p1n + " au pouvoir") : dir === "p2" ? (p2n + " au pouvoir") : "Équilibré";',
'    var dirCol = dir === "p1" ? "var(--green,#00e676)" : dir === "p2" ? "var(--blue,#3b9eff)" : "var(--amber,#fbbf24)";',
'    html += "<div style=\\"display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;padding:8px 10px;background:rgba(255,255,255,.03);border-radius:8px\\">";',
'    html += "<div style=\\"font-size:13px;font-weight:700;color:var(--text,#fff)\\">" + p1n + " <span style=\\"color:var(--text3,#94a3b8);font-weight:400\\">vs</span> " + p2n + "</div>";',
'    html += "<div style=\\"font-size:12px;font-family:monospace;color:" + dirCol + ";font-weight:700\\">▲ " + dirLabel + " (" + conf + "%)</div>";',
'    html += "</div>";',
'    // KPIs',
'    html += "<div style=\\"display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:14px\\">";',
'    var kpis = [',
'      { lbl: "K-Flow", val: (mom.kfs_confidence || 0) + "%", col: mom.kfs_direction === "p1" ? "var(--green)" : mom.kfs_direction === "p2" ? "var(--blue)" : "var(--text3)" },',
'      { lbl: "SM Flow", val: (mom.sm_confidence || 0) + "%", col: mom.sm_direction === "p1" ? "var(--green)" : mom.sm_direction === "p2" ? "var(--blue)" : "var(--text3)" },',
'      { lbl: "Shift", val: (mom.momentum_shift || 0).toFixed(2), col: "var(--amber)" },',
'      { lbl: "Points", val: mom.points_tracked || 0, col: "var(--text2)" }',
'    ];',
'    kpis.forEach(function(k) {',
'      html += "<div style=\\"text-align:center;padding:8px 4px;background:rgba(255,255,255,.02);border:1px solid rgba(255,255,255,.06);border-radius:6px\\">";',
'      html += "<div style=\\"font-size:9px;text-transform:uppercase;letter-spacing:.5px;color:var(--text3,#94a3b8)\\">" + k.lbl + "</div>";',
'      html += "<div style=\\"font-size:15px;font-weight:800;font-family:monospace;color:" + k.col + ";margin-top:2px\\">" + k.val + "</div>";',
'      html += "</div>";',
'    });',
'    html += "</div>";',
'    // Graphe principal',
'    var series = data.series || null;',
'    html += "<div style=\\"font-size:13px;font-weight:700;color:var(--text,#fff);margin-bottom:6px\\">📈 Force du joueur par jeu</div>";',
'    if (series && series.p1_series && series.p1_series.length > 0) {',
'      html += _momPopupChart(series.p1_series, series.p2_series, series.labels || [], series.games || []);',
'    } else {',
'      html += "<div style=\\"color:var(--text3);font-size:12px;padding:20px;text-align:center;background:rgba(255,255,255,.02);border-radius:8px\\">Pas encore assez de jeux joués (minimum 2 jeux).</div>";',
'    }',
'    // Détail par jeu (chips)',
'    if (series && series.games && series.games.length > 0) {',
'      html += "<div style=\\"font-size:13px;font-weight:700;color:var(--text,#fff);margin:14px 0 6px\\">🔍 Détail par jeu</div>";',
'      html += "<div style=\\"display:flex;flex-wrap:wrap;gap:4px\\">";',
'      series.games.forEach(function(g) {',
'        var bg = g.brk ? "rgba(255,99,132,.15)" : "rgba(255,255,255,.03)";',
'        var border = g.brk ? "rgba(255,99,132,.4)" : "rgba(255,255,255,.08)";',
'        var txt = g.w === 1 ? p1n.charAt(0) : p2n.charAt(0);',
'        var col = g.w === 1 ? "var(--green,#00e676)" : "var(--blue,#3b9eff)";',
'        var title = (g.brk ? "BREAK " : "HOLD ") + (g.w === 1 ? p1n : p2n) + " (run " + g.run + ")";',
'        html += "<span title=\\"" + title + "\\" style=\\"display:inline-flex;align-items:center;justify-content:center;min-width:28px;height:24px;padding:0 6px;background:" + bg + ";border:1px solid " + border + ";border-radius:4px;font-size:10px;font-weight:700;color:" + col + ";font-family:monospace\\">" + txt + (g.brk ? "⚡" : "") + "</span>";',
'      });',
'      html += "</div>";',
'      html += "<div style=\\"font-size:10px;color:var(--text3,#94a3b8);margin-top:6px\\">⚡ = break · couleur = gagnant · run = jeux consécutifs</div>";',
'    }',
'    // Série en cours (run) + breaks',
'    var sm = data.serve_momentum || {};',
'    if (sm.run && sm.run.player) {',
'      var runName = sm.run.player === 1 ? p1n : p2n;',
'      var runCol = sm.run.player === 1 ? "var(--green,#00e676)" : "var(--blue,#3b9eff)";',
'      html += "<div style=\\"margin-top:12px;padding:8px 10px;background:rgba(255,255,255,.03);border-radius:8px;font-size:12px\\">";',
'      html += "<span style=\\"color:var(--text3,#94a3b8)\\">Série en cours : </span>";',
'      html += "<b style=\\"color:" + runCol + "\\">" + runName + " " + sm.run.len + " pts</b>";',
'      if (sm.breaks_recent != null) html += "<span style=\\"color:var(--text3,#94a3b8);margin-left:12px\\">Breaks (5 jeux) : <b style=\\"color:var(--amber)\\">" + sm.breaks_recent + "</b></span>";',
'      html += "</div>";',
'    }',
'    content.innerHTML = html;',
'    var modal = document.getElementById("mom-popup-modal");',
'    if (modal) modal.style.display = "flex";',
'  } catch (e) { console.error("[MomPopup]", e); }',
'}',
'function closeMomPopup() {',
'  var modal = document.getElementById("mom-popup-modal");',
'  if (modal) modal.style.display = "none";',
'}',
'// Graphe dual-courbe : force P1 vs P2 par jeu (0-100), aire graduée, marqueurs break',
'function _momPopupChart(p1, p2, labels, games) {',
'  if ((!p1 || p1.length < 1) && (!p2 || p2.length < 1)) return "<div style=\\"color:var(--text3);font-size:12px\\">Pas assez de données</div>";',
'  var n = Math.max(p1 ? p1.length : 0, p2 ? p2.length : 0);',
'  if (n < 2) return "<div style=\\"color:var(--text3);font-size:12px;padding:12px;text-align:center\\">Minimum 2 jeux requis pour tracer la courbe</div>";',
'  var w = 500, h = 200, padL = 34, padR = 14, padT = 14, padB = 28;',
'  var plotW = w - padL - padR, plotH = h - padT - padB;',
'  function ym(v) { return padT + plotH - (Math.max(0, Math.min(100, v)) / 100) * plotH; }',
'  function xm(i) { return padL + (n <= 1 ? plotW / 2 : (i / (n - 1)) * plotW); }',
'  var yMid = ym(50);',
'  var z1 = "<rect x=" + padL + " y=" + padT + " width=" + plotW + " height=" + (yMid - padT) + " fill=\\"rgba(0,230,118,.04)\\"/>";',
'  var z2 = "<rect x=" + padL + " y=" + yMid + " width=" + plotW + " height=" + (padT + plotH - yMid) + " fill=\\"rgba(0,119,255,.04)\\"/>";',
'  var grid = "";',
'  [0,25,50,75,100].forEach(function(v) {',
'    var gy = ym(v);',
'    grid += "<line x1=" + padL + " y1=" + gy + " x2=" + (w - padR) + " y2=" + gy + " stroke=\\"rgba(255,255,255," + (v === 50 ? ".15" : ".05") + ")\\" stroke-width=\\"1\\"" + (v === 50 ? " stroke-dasharray=\\"6 4\\"" : "") + "/>";',
'    grid += "<text x=" + (padL - 4) + " y=" + (gy + 3) + " text-anchor=\\"end\\" font-size=\\"8\\" fill=\\"rgba(255,255,255,.3)\\" font-family=\\"monospace\\">" + v + "</text>";',
'  });',
'  var xlabels = "";',
'  for (var i = 0; i < n; i++) { xlabels += "<text x=" + xm(i).toFixed(1) + " y=" + (h - padB + 14) + " text-anchor=\\"middle\\" font-size=\\"8\\" fill=\\"rgba(255,255,255,.35)\\" font-family=\\"monospace\\">" + (labels[i] || ("J" + (i+1))) + "</text>"; }',
'  function path(s) {',
'    if (!s || s.length < 1) return "";',
'    return s.map(function(v,i){ return (i===0?"M":"L") + xm(i).toFixed(1) + " " + ym(v).toFixed(1); }).join(" ");',
'  }',
'  // Aire graduée entre courbe P1 et médiane 50',
'  var areaP1 = "";',
'  if (p1 && p1.length > 1) {',
'    var topPts = p1.map(function(v,i){ return xm(i).toFixed(1) + " " + ym(v).toFixed(1); });',
'    var baseLine = p1.map(function(v,i){ return xm(i).toFixed(1) + " " + ym(50).toFixed(1); }).reverse();',
'    areaP1 = "<path d=\\"M" + topPts.join(" L") + " L" + baseLine.join(" L") + " Z\\" fill=\\"url(#momGrad)\\" opacity=\\"0.3\\"/>";',
'  }',
'  // Marqueurs break (losanges rouges)',
'  var breakMarks = "";',
'  if (games && games.length) {',
'    games.forEach(function(g, i) {',
'      if (g.brk && i < n) {',
'        var cx = parseFloat(xm(i).toFixed(1));',
'        var serVal = g.w === 1 ? (p1 ? p1[i] : 50) : (p2 ? p2[i] : 50);',
'        var cy = parseFloat(ym(serVal || 50).toFixed(1));',
'        breakMarks += "<polygon points=\\"" + cx + "," + (cy-5) + " " + (cx+5) + "," + cy + " " + cx + "," + (cy+5) + " " + (cx-5) + "," + cy + "\\" fill=\\"rgba(255,99,132,.9)\\" stroke=\\"#fff\\" stroke-width=\\"0.5\\"/>";',
'      }',
'    });',
'  }',
'  function dots(s, color) {',
'    if (!s) return "";',
'    return s.map(function(v,i){ var cx=xm(i).toFixed(1), cy=ym(v).toFixed(1); return "<circle cx=" + cx + " cy=" + cy + " r=\\"3\\" fill=" + color + " stroke=\\"rgba(0,0,0,.4)\\" stroke-width=\\"1\\"/>"; }).join("");',
'  }',
'  var defs = "<defs><linearGradient id=\\"momGrad\\" x1=\\"0\\" y1=\\"0\\" x2=\\"0\\" y2=\\"1\\"><stop offset=\\"0%\\" stop-color=\\"#00e676\\" stop-opacity=\\"0.5\\"/><stop offset=\\"100%\\" stop-color=\\"#00e676\\" stop-opacity=\\"0\\"/></linearGradient></defs>";',
'  var lineP1 = p1 && p1.length > 1 ? "<path d=\\"" + path(p1) + "\\" fill=\\"none\\" stroke=\\"var(--green,#00e676)\\" stroke-width=\\"2.5\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/>" : "";',
'  var lineP2 = p2 && p2.length > 1 ? "<path d=\\"" + path(p2) + "\\" fill=\\"none\\" stroke=\\"var(--blue,#3b9eff)\\" stroke-width=\\"2.5\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/>" : "";',
'  return "<svg width=" + w + " height=" + h + " viewBox=\\"0 0 " + w + " " + h + "\\" style=\\"width:100%;height:auto;display:block\\">" + defs + z1 + z2 + grid + xlabels + areaP1 + "<line x1=" + padL + " y1=" + yMid + " x2=" + (w-padR) + " y2=" + yMid + " stroke=\\"rgba(255,255,255,.25)\\" stroke-width=\\"1.2\\" stroke-dasharray=\\"6 4\\"/>" + lineP1 + lineP2 + dots(p1, "var(--green,#00e676)") + dots(p2, "var(--blue,#3b9eff)") + breakMarks + "</svg>" +',
'    "<div style=\\"display:flex;justify-content:center;gap:18px;margin-top:6px;font-size:11px;font-family:monospace;color:var(--text3,#94a3b8)\\"><span><span style=\\"display:inline-block;width:14px;height:3px;background:var(--green,#00e676);border-radius:2px;vertical-align:middle\\"></span> Force P1</span><span><span style=\\"display:inline-block;width:14px;height:3px;background:var(--blue,#3b9eff);border-radius:2px;vertical-align:middle\\"></span> Force P2</span><span><span style=\\"display:inline-block;width:6px;height:6px;background:rgba(255,99,132,.9);transform:rotate(45deg);vertical-align:middle\\"></span> Break</span><span style=\\"opacity:.5\\">— 50% parité</span></div>";',
'}',
'</script>'
].join('\n');

const newH = h.slice(0, idx + INSERT_AFTER.length) + MOMENTUM_BLOCK + h.slice(idx + INSERT_AFTER.length);
fs.writeFileSync(FILE, newH, 'utf8');
console.log('OK: momentum popup inserted, +' + MOMENTUM_BLOCK.length + ' bytes');
